async (params, browser) => {
  // Open Todoist
  await browser.open('https://app.todoist.com/app/today')

  // Wait for page
  await browser.waitForSelector('main, .content, [class*="task"]', 15000)

  // Let page render
  await browser.wait(2500)

  // Click Add Task button
  const open_add = await browser.evaluate(`const addBtn = document.querySelector('[data-testid="quick-add-task-button"], button[class*="plus"], .add_task, [class*="add_task"], button[aria-label*="Add task"], button[aria-label*="add task"]'); if (addBtn) { addBtn.click(); return { clicked: true }; } document.dispatchEvent(new KeyboardEvent('keydown', { key: 'q', code: 'KeyQ', keyCode: 81, bubbles: true })); return { clicked: false, used_shortcut: true };`)

  // Wait for task editor
  await browser.wait(1500)

  // Type task name
  const type_task = await browser.evaluate(`const input = document.querySelector('[data-testid="task-name-input"], .task_editor__content_field, [contenteditable="true"][class*="task"], [class*="task_editor"] [contenteditable], textarea[class*="task"], [class*="quick_add"] [contenteditable], [class*="quick_add"] textarea, [class*="quick_add"] input'); if (input) { input.focus(); if (input.tagName === 'TEXTAREA' || input.tagName === 'INPUT') { input.value = '' + params.task_name + ''; input.dispatchEvent(new Event('input', { bubbles: true })); } else { document.execCommand('insertText', false, '' + params.task_name + ''); } return { typed: true }; } return { typed: false, error: 'Could not find task input field' };`)

  // Wait before submit
  await browser.wait(1000)

  // Submit task
  const result = await browser.evaluate(`const submitBtn = document.querySelector('[data-testid="task-editor-submit-button"], button[type="submit"], .task_editor__submit_btn, [class*="task_editor"] button[type="submit"], [class*="quick_add"] button[type="submit"]'); if (submitBtn) { submitBtn.click(); return { submitted: true, task_name: '' + params.task_name + '' }; } return { submitted: false, error: 'Could not find submit button' };`)

  return result
}
